  1	import * as React from 'react';
  2	import { AccessKeyMetadata, Tag } from '@aws-sdk/client-iam';
  3	import { AccessKeyStatus } from '@odf/core/constants/s3-iam';
  4	import DeleteAccessKeyModal from '@odf/core/modals/s3-iam/DeleteAccessKeyModal';
  5	import EditDescriptionTagModal from '@odf/core/modals/s3-iam/EditDescriptonTagModal';
  6	import UpdateAccessKeyModal from '@odf/core/modals/s3-iam/UpdateAccessKeyModal';
  7	import { DASH, useCustomTranslation } from '@odf/shared';
  8	import { IamCommands } from '@odf/shared/iam';
  9	import {
 10	  GreenCheckCircleIcon,
 11	  useModal,
 12	} from '@openshift-console/dynamic-plugin-sdk';
 13	import { LaunchModal } from '@openshift-console/dynamic-plugin-sdk/lib/app/modal-support/ModalProvider';
 14	import { TFunction } from 'react-i18next';
 15	import {
 16	  Card,
 17	  CardBody,
 18	  CardHeader,
 19	  CardTitle,
 20	  Dropdown,
 21	  DropdownItem,
 22	  DropdownList,
 23	  Flex,
 24	  FlexItem,
 25	  GridItem,
 26	  Label,
 27	  MenuToggle,
 28	  MenuToggleElement,
 29	  Text,
 30	  Title,
 31	} from '@patternfly/react-core';
 32	import { BanIcon, EllipsisVIcon } from '@patternfly/react-icons';
 33	
 34	type AccessKeyCardProps = {
 35	  accessKeyCard: AccessKeyMetadata;
 36	  accessKeyNumber: number;
 37	  tags: Tag[];
 38	  iamClient: IamCommands;
 39	  refreshTokens: () => void;
 40	};
 41	
 42	type DropdownToggleProps = {
 43	  toggleRef: React.Ref<MenuToggleElement>;
 44	  isOpen: boolean;
 45	  setIsOpen: (open: boolean) => void;
 46	};
 47	
 48	type HeaderProps = {
 49	  headerProps: {
 50	    launchModal: LaunchModal;
 51	    accessKeyCard: AccessKeyMetadata;
 52	    refreshTokens: () => void;
 53	    iamClient: IamCommands;
 54	  };
 55	};
 56	
 57	const DropdownToggle: React.FC<DropdownToggleProps> = ({
 58	  toggleRef,
 59	  isOpen,
 60	  setIsOpen,
 61	}) => (
 62	  <MenuToggle
 63	    ref={toggleRef}
 64	    isExpanded={isOpen}
 65	    onClick={() => setIsOpen(!isOpen)}
 66	    variant="plain"
 67	  >
 68	    <EllipsisVIcon aria-hidden="true" />
 69	  </MenuToggle>
 70	);
 71	const renderStatusLabel = (status: string, t: TFunction) => (
 72	  <Label
 73	    icon={
 74	      status === AccessKeyStatus.ACTIVE ? <GreenCheckCircleIcon /> : <BanIcon />
 75	    }
 76	  >
 77	    {status === AccessKeyStatus.ACTIVE ? t('Active') : t('Deactivated')}
 78	  </Label>
 79	);
 80	
 81	const HeaderActions: React.FC<HeaderProps> = ({ headerProps }) => {
 82	  const { launchModal, accessKeyCard, refreshTokens, iamClient } = headerProps;
 83	  const [isOpen, setIsOpen] = React.useState<boolean>(false);
 84	  const onSelect = () => {
 85	    setIsOpen(false);
 86	  };
 87	  const { t } = useCustomTranslation();
 88	  const dropdownItems = React.useMemo(
 89	    () => (
 90	      <>
 91	        <DropdownItem
 92	          key="activate-deactivate"
 93	          onClick={() =>
 94	            launchModal(UpdateAccessKeyModal, {
 95	              isOpen: true,
 96	              extraProps: {
 97	                name: accessKeyCard.UserName,
 98	                AccessKeyId: accessKeyCard.AccessKeyId,
 99	                updateStatusTo:
100	                  accessKeyCard.Status === AccessKeyStatus.ACTIVE
101	                    ? AccessKeyStatus.INACTIVE
102	                    : AccessKeyStatus.ACTIVE,
103	                iamClient,
104	                refreshTokens,
105	              },
106	            })
107	          }
108	        >
109	          {accessKeyCard.Status === AccessKeyStatus.ACTIVE
110	            ? t('Deactivate access key')
111	            : t('Activate access key')}
112	        </DropdownItem>
113	
114	        <DropdownItem
115	          key="edit"
116	          onClick={() =>
117	            launchModal(EditDescriptionTagModal, {
118	              isOpen: true,
119	              extraProps: {
120	                name: accessKeyCard.UserName,
121	                AccessKeyId: accessKeyCard.AccessKeyId,
122	                iamClient,
123	                refreshTokens,
124	              },
125	            })
126	          }
127	        >
128	          {t('Edit description tag')}
129	        </DropdownItem>
130	        <DropdownItem
131	          key="delete"
132	          onClick={() =>
133	            launchModal(DeleteAccessKeyModal, {
134	              isOpen: true,
135	              extraProps: {
136	                accessKeyCard,
137	                iamClient,
138	                refreshTokens,
139	              },
140	            })
141	          }
142	        >
143	          {t('Delete access key')}
144	        </DropdownItem>
145	      </>
146	    ),
147	    [launchModal, accessKeyCard, iamClient, refreshTokens, t]
148	  );
149	
150	  const renderToggle = React.useCallback(
151	    (toggleRef: React.Ref<MenuToggleElement>) => (
152	      <DropdownToggle
153	        toggleRef={toggleRef}
154	        isOpen={isOpen}
155	        setIsOpen={setIsOpen}
156	      />
157	    ),
158	    [isOpen, setIsOpen]
159	  );
160	
161	  return (
162	    <Dropdown
163	      onSelect={onSelect}
164	      toggle={renderToggle}
165	      isOpen={isOpen}
166	      onOpenChange={setIsOpen}
167	    >
168	      <DropdownList>{dropdownItems}</DropdownList>
169	    </Dropdown>
170	  );
171	};
172	
173	const AccessKeyCard: React.FC<AccessKeyCardProps> = ({
174	  accessKeyCard,
175	  accessKeyNumber,
176	  tags,
177	  refreshTokens,
178	  iamClient,
179	}) => {
180	  const { t } = useCustomTranslation();
181	  const launchModal = useModal();
182	
183	  const descriptionTag = React.useMemo(
184	    () =>
185	      tags.find((tag) => tag.Key === accessKeyCard.AccessKeyId)?.Value || DASH,
186	    [tags, accessKeyCard.AccessKeyId]
187	  );
188	
189	  return (
190	    <GridItem xl={4} lg={6} md={6} sm={12} className="pf-v6-u-my-md">
191	      <Card>
192	        <CardHeader
193	          actions={{
194	            actions: (
195	              <HeaderActions
196	                headerProps={{
197	                  launchModal,
198	                  accessKeyCard,
199	                  refreshTokens,
200	                  iamClient,
201	                }}
202	              />
203	            ),
204	            hasNoOffset: false,
205	          }}
206	        >
207	          <Flex justifyContent={{ default: 'justifyContentSpaceBetween' }}>
208	            <FlexItem>
209	              <CardTitle>{`${t('Access key')} ${accessKeyNumber}`} </CardTitle>
210	              <Text>{accessKeyCard.AccessKeyId || DASH}</Text>
211	            </FlexItem>
212	            <FlexItem>{renderStatusLabel(accessKeyCard.Status, t)}</FlexItem>
213	          </Flex>
214	        </CardHeader>
215	        <CardBody className="pf-v6-u-mt-md">
216	          <Title headingLevel="h4" className="pf-v6-u-mb-sm">
217	            {t('Description tag')}
218	          </Title>
219	          <Text>{descriptionTag}</Text>
220	        </CardBody>
221	      </Card>
222	    </GridItem>
223	  );
224	};
225	
226	export default AccessKeyCard;

